INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2023/06/30 12:00:00", 10001, 1, 2, 126401, 1, 1.47, 0.0, "いらっしゃいませっ♪\nキャラバンコインを使って\n買い物ができますよっ！", -470.0, 2002, "クローチェ", "2023/09/22 14:59:59", 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2023/06/30 12:00:00", 10002, 2, 1, 126401, 1, 2.15, 0.0, "素敵な品が揃ってるので\nたーっくさん買っていって\nくださいねっ♪", -470.0, 2002, "クローチェ", "2023/09/22 14:59:59", 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2023/06/30 12:00:00", 10003, 1, 2, 126501, 1, 0.0, 0.0, "ショップへようこそ\nキャラバンコインはこちら\nで買い物に使えますよ", -470.0, 2002, "ライラエル", "2023/09/22 14:59:59", 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2023/06/30 12:00:00", 10004, 2, 1, 126501, 1, 0.0, 0.0, "こちらのショップで\n買い物をして、素敵な\n旅を楽しんでくださいね", -470.0, 2002, "ライラエル", "2023/09/22 14:59:59", 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2023/09/15 15:00:00", 10005, 1, 2, 127702, 2, 0.0, 0.0, "いらっしゃいませ\nキャラバンコインを使って\nお買い物ができますよ", -470.0, 2002, "リンド", "2023/12/22 14:59:59", 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2023/09/15 15:00:00", 10006, 2, 2, 127702, 2, 0.0, 0.0, "ショップの掃除は完璧です\n姫さま直営のお店として\n当然のことですから", -470.0, 2002, "リンド", "2023/12/22 14:59:59", 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2023/09/15 15:00:00", 10007, 1, 1, 127802, 2, 0.0, 0.0, "ショップへようこそ\nキャラバンコインと品物を\n交換できるんで、よければ", -470.0, 2002, "ヴルム", "2023/12/22 14:59:59", 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2023/09/15 15:00:00", 10008, 2, 1, 127802, 2, 6.5, 0.0, "なんで店番なんか…\nま、やりますけど\n好きな品物をどうぞ", -470.0, 2002, "ヴルム", "2023/12/22 14:59:59", 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2023/12/15 15:00:00", 10009, 1, 1, 129602, 3, 0.0, 0.0, "──いらっしゃいませ\n買い物しても、いいですよ\nキャラバンコインがあれば", -470.0, 2002, "アネモネ", "2024/03/22 14:59:59", 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2023/12/15 15:00:00", 10010, 2, 1, 129602, 3, 0.0, 0.0, "──もっと笑顔がほしい？\nいくらコインを積まれても\n売れない物はありますから", -470.0, 2002, "アネモネ", "2024/03/22 14:59:59", 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2023/12/15 15:00:00", 10011, 1, 1, 129701, 3, 0.0, 0.0, "ようこそおいでなんし\nキャラバンコインをこちら\nで交換して進ぜんしょう", -470.0, 2002, "ネフィ=ネラ", "2024/03/22 14:59:59", 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2023/12/15 15:00:00", 10012, 2, 1, 129701, 3, 6.2, 0.0, "ところで、お前さまは\nいくらで贖えるのか喃？\n──フフ、冗談でありんす", -470.0, 2002, "ネフィ=ネラ", "2024/03/22 14:59:59", 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2024/03/15 15:00:00", 10013, 1, 5, 130301, 4, 3.1, 0.0, "い、いらっしゃいませっ！\n…くっ…このあたくし様が\n店番なんて…屈辱ですわっ", -470.0, 2002, "カノン", "2024/06/22 14:59:59", 3);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2024/03/15 15:00:00", 10014, 2, 2, 130301, 4, 6.15, 0.0, "あら、あたくしをご所望？\nお生憎様、そんな小銭では\n…買えちゃうんですの！？", -470.0, 2002, "カノン", "2024/06/22 14:59:59", 3);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2024/03/15 15:00:00", 10015, 1, 2, 130401, 4, 0.0, 0.0, "いらっしゃいませ～♪\nきゃらばんこいん？を\n交換できるんだってー", -470.0, 2002, "ナーナ", "2024/06/22 14:59:59", 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2024/03/15 15:00:00", 10016, 2, 1, 130401, 4, 3.35, 0.0, "甘いのくれたら、\nお礼にナーナの拾った\n松ぼっくりあげちゃうよ！", -470.0, 2002, "ナーナ", "2024/06/22 14:59:59", 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2024/06/15 15:00:00", 10017, 1, 1, 130502, 5, 0.0, 0.0, "ショップへようこそ\nこの鳳凰が、皆さんに\n祝福を差し上げましょう", -470.0, 2002, "ホウオウ", "2024/09/22 14:59:59", 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2024/06/15 15:00:00", 10018, 2, 1, 130502, 5, 3.18, 0.0, "ほーちゃんと呼ぶ権利は\n売っていませんよ？\n騎士さんへの、特別です！", -470.0, 2002, "ホウオウ", "2024/09/22 14:59:59", 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2024/06/15 15:00:00", 10019, 3, 4, 130503, 5, 0.0, 0.0, "うﾞぇぇえんっ！まﾞだごの\n格好になっぢゃいまじだ！\n寄付をお願いじまず～っ！", -470.0, 2002, "ホウオウ", "2024/09/22 14:59:59", 4);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2024/06/15 15:00:00", 10020, 1, 2, 123301, 5, 4.9, 0.0, "おっすー♪\nなんでも交換してけー\nカリザきゅん以外で", -470.0, 2002, "ネア", "2024/09/22 14:59:59", 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2024/06/15 15:00:00", 10021, 2, 2, 123301, 5, 4.8, 0.0, "ところで、騎士きゅんは\nおいくら万ルピ？\nジョーダンぬ・き・で♡", -470.0, 2002, "ネア", "2024/09/22 14:59:59", 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2024/09/15 15:00:00", 10022, 1, 1, 133301, 6, 4.922, 0.0, "ケッ、なんでオレ様が店番\nなんざ…って来んなキイロ\nオレは売りモンじゃねー！", -470.0, 2002, "カリザ", "2024/12/22 14:59:59", 3);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2024/09/15 15:00:00", 10023, 2, 5, 133301, 6, 9.638, 0.0, "い、言わなきゃダメか？\n「…いらっしゃいませ…」\nクソッ、笑うんじゃねー！", -470.0, 2002, "カリザ", "2024/12/22 14:59:59", 3);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2024/09/15 15:00:00", 10024, 1, 2, 133401, 6, 2.88, 0.0, "ショップへようこそ～\nネラさまの腹心…的な私が\n店番させていただきま～す", -470.0, 2002, "ミーア", "2024/12/22 14:59:59", 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2024/09/15 15:00:00", 10025, 2, 1, 133401, 6, 4.818, 0.0, "私の抜け殻とか、\n需要ありますかね～…\nって冗談ですよ、冗談！", -470.0, 2002, "ミーア", "2024/12/22 14:59:59", 5);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2024/12/15 15:00:00", 10026, 1, 1, 133002, 7, 1.78, 0.0, "へい、らっしゃい\nさ、騎士氏。冥土の土産は\nなにがいいですか？", -470.0, 2002, "グレイス", "2025/03/22 14:59:59", 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2024/12/15 15:00:00", 10027, 2, 7, 133002, 7, 6.15, 0.0, "商品をお買い上げ毎に\nグレイスちゃんポイントを\n差し上げます。嘘ですが", -470.0, 2002, "グレイス", "2025/03/22 14:59:59", 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2024/12/15 15:00:00", 10028, 1, 2, 133102, 7, 4.28, 0.0, "ようこそいらっしゃいませ\n…接客とは、このような\n振舞で宜しいでしょうか？", -470.0, 2002, "ヴァイオレット", "2025/03/22 14:59:59", 6);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2024/12/15 15:00:00", 10029, 2, 1, 133102, 7, 0.0, 0.0, "じめじめした商品は\nございませんので\n安心してお買い求め下さい", -470.0, 2002, "ヴァイオレット", "2025/03/22 14:59:59", 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2025/03/15 15:00:00", 10030, 1, 1, 136902, 8, 5.53, 0.0, "いらっしゃいましぇでしゅ\n何をお求めでしゅか？\nたこ焼きもありましゅよ！", -470.0, 2002, "ルルィ", "2025/06/23 14:59:59", 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2025/03/15 15:00:00", 10031, 2, 7, 136902, 8, 6.05, 0.0, "そのコイン…ピカピカで、\n集めたくなっちゃいましゅ\nタコ釣られされちゃう～…", -470.0, 2002, "ルルィ", "2025/06/23 14:59:59", 9);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2025/03/15 15:00:00", 10032, 1, 1, 137001, 8, 0.0, 0.0, "姫のご友人ならば\n礼儀を尽くすのが爺の務め\nさ、望みの物を言いたまえ", -470.0, 2002, "デュラン", "2025/06/23 14:59:59", 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2025/03/15 15:00:00", 10033, 2, 1, 137001, 8, 0.0, 0.0, "キャラバンコインではなく\n首で支払って貰えんかのぅ\n…冗談であるぞ？", -470.0, 2002, "デュラン", "2025/06/23 14:59:59", 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2025/06/16 15:00:00", 10034, 1, 2, 135902, 9, 0.0, 0.0, "おう\n好きなもん持ってきな", -470.0, 2002, "サツキ", "2025/09/23 14:59:59", 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2025/06/16 15:00:00", 10035, 2, 6, 135902, 9, 4.935, 0.0, "宵越しの銭を持つような\n野暮いマネぁしくさんな\nツキが落ちてもしらねぇぜ", -470.0, 2002, "サツキ", "2025/09/23 14:59:59", 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2025/06/16 15:00:00", 10036, 1, 5, 135802, 9, 7.441, 0.0, "ら、ら、らっしゃっせ…\nなんかほしいもん、ある？\nか、かき氷とか、ど…？", -470.0, 2002, "ユキノ", "2025/09/23 14:59:59", 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2025/06/16 15:00:00", 10037, 2, 7, 135802, 9, 0.0, 0.0, "そ、そんな見ねぇで…\nあては、売りもんじゃ\nねぇよ…？", -470.0, 2002, "ユキノ", "2025/09/23 14:59:59", 7);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2025/09/16 15:00:00", 10038, 1, 2, 130901, 10, 2.295, 0.0, "クルルをお求めですかっ？\nそれならお礼に、こちらの\n宝石もどうぞですよ～♪", -470.0, 2002, "クルル", "2025/12/22 14:59:59", 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2025/09/16 15:00:00", 10039, 2, 6, 130901, 10, 6.281, 0.0, "はっ！　ヒーローさんから\nお代なんて頂けないです！\nどうぞどうぞ…え、ダメ？", -470.0, 2002, "クルル", "2025/12/22 14:59:59", 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2025/09/16 15:00:00", 10040, 1, 1, 137701, 10, 5.549, 0.0, "よぅ！　今日の俺さまは\n門番じゃなく、店番だぜ\nメモピ～スフィア～てな！", -470.0, 2002, "ヴォルガーノ", "2025/12/22 14:59:59", 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2025/09/16 15:00:00", 10041, 2, 6, 137701, 10, 2.64, 0.0, "…リマさんのブロマイド？\n買い取るに決まってらぁ！\nなんでも持ってけ泥棒っ！", -470.0, 2002, "ヴォルガーノ", "2025/12/22 14:59:59", 3);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2025/12/15 15:00:00", 10042, 1, 4, 132801, 11, 7.642, 0.0, "こ、この格好は…ヴルムが\n集客効果があると言って…\n…本当でしょうか？", -470.0, 2002, "ライラエル", "2026/03/23 11:59:59", 7);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2025/12/15 15:00:00", 10043, 2, 1, 132802, 11, 0.0, 0.0, "この我に店番させるとは…\n全て買わねば許さぬぞ\n我が国庫に貢献するが良い", -470.0, 2002, "ライラエル", "2026/03/23 11:59:59", 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2025/12/15 15:00:00", 10044, 1, 1, 134502, 11, 0.0, 0.0, "アナライズっ！\n本日のオススメ商品は～…\nこちらですっ♪", -470.0, 2002, "クローチェ", "2026/03/23 11:59:59", 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2025/12/15 15:00:00", 10045, 2, 1, 134501, 11, 3.72, 0.0, "ギガンティックローチェ、\nおひとついかがですかっ？\n格納庫用意して下さいねっ", -470.0, 2002, "クローチェ", "2026/03/23 11:59:59", 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2026/03/16 12:00:00", 10046, 1, 1, 138201, 12, 4.991, 0.0, "番頭も、飯事の如き営み\nなれば。愛らしき稚児らで\n千客万来といきませぬか喃", -470.0, 2002, "ネフィ＝ネラ", "2026/06/22 11:59:59", 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2026/03/16 12:00:00", 10047, 2, 4, 138201, 12, 3.877, 0.0, "国を営むに金子は必須也…\nどうか御恵みくだしゃんせ\n誠心を以て報恩致しまする", -470.0, 2002, "ネフィ＝ネラ", "2026/06/22 11:59:59", 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2026/03/16 12:00:00", 10048, 1, 6, 136001, 12, 1.71, 0.0, "あぅっ…！　天井が低くて\n頭をぶつけてしまって…\nわたしが、大きいだけ…？", -470.0, 2002, "アラクネ", "2026/06/22 11:59:59", 4);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("2026/03/16 12:00:00", 10049, 2, 2, 136001, 12, 5.32, 0.0, "いらっしゃいませ騎士さま\nくつろいでいって下さいね\nもし叶うなら…永遠に…", -470.0, 2002, "アラクネ", "2026/06/22 11:59:59", 5);
